var e=[{id:`L2_1`,type:`dialog`,speaker:`NEWCOMER_NPC_DREAM_NULL`,text:{KOREA:`갑자기 저 로봇들은 뭐야?!`,JPN:`いきなりあのロボットたちは何！？`,ENG:`What are those robots?!`,TWN:`怎麼突然冒出那些多機器人？！`},stage:{bg:`CLOSE`,bgm:`BATTLE_SUMMER_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:`PUPPET_NPC_SUPPLEMENT_NULL`,text:{KOREA:`인공지능은 탑재되지 않은 것 같아.`,JPN:`人工知能は搭載されてないみたい。`,ENG:`I don't think they have any AI implementation.`,TWN:`好像沒有搭載人工智慧。`},stage:{bg:`CLOSE`,bgm:`BATTLE_SUMMER_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:`RUNNER_OZ_NULL_NULL`,text:{KOREA:`수영장에 로봇이라니… 뭔가 이상하게 돌아가는데.`,JPN:`プールにロボットって……なんかおかしいことになってる。`,ENG:`Robots in a pool...? Something doesn't feel right.`,TWN:`泳游池裡竟然有機器人…感覺不太對勁。`},stage:{bg:`CLOSE`,bgm:`BATTLE_SUMMER_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}}];export{e as default};